import akka.actor.{Actor, ActorSystem, Props}
import java.util.concurrent.atomic.AtomicLong

sealed trait AccountMessage
case class Deposit(amount: Long) extends AccountMessage
case class Withdraw(amount: Long) extends AccountMessage
case object GetBalance extends AccountMessage
case class BalanceResponse(balance: Long)

class AccountActor extends Actor {
  private val balance = new AtomicLong(0L)

  def receive: Receive = {
    case Deposit(amount) =>
      if (amount > 0) {
        balance.addAndGet(amount)
      }
      
    case Withdraw(amount) =>
      if (amount > 0) {
        var currentBalance = balance.get()
        var newBalance = currentBalance - amount
        
        while (newBalance >= 0 && !balance.compareAndSet(currentBalance, newBalance)) {
          currentBalance = balance.get()
          newBalance = currentBalance - amount
        }
      }
      
    case GetBalance =>
      sender() ! BalanceResponse(balance.get())
  }
}

object AccountSystem {
  def main(args: Array[String]): Unit = {
    val system = ActorSystem("AccountSystem")
    val accountActor = system.actorOf(Props[AccountActor], "accountActor")
    
    accountActor ! Deposit(1000)
    accountActor ! Withdraw(200)
    accountActor ! Deposit(500)
    accountActor ! Withdraw(100)
  }
